param([Parameter(Mandatory=$true)][string]$IncomingRoot,[Parameter(Mandatory=$true)][string]$RunId,[int]$TimeoutSeconds=300)
$ErrorActionPreference='Stop';$root="$env:USERPROFILE\NoraPhase2J";$run=Join-Path $root $RunId;New-Item -ItemType Directory -Force $run|Out-Null;$term='C:\Program Files\Darwinex MetaTrader 5\terminal64.exe';$seed='C:\Program Files\Darwinex MetaTrader 5\backtest_run.ini';$name='nora_phase2_condition_tester_v1.csv';$stages=[ordered]@{tester_configuration_loaded=$false;testing_agent_started=$false;ea_loaded=$false;ea_initialized=$false;fixture_execution_started=$false;result_csv_written=$false;fixture_execution_completed=$false;tester_completed=$false;terminal_shutdown=$false}
function Save([string]$status,[string]$error=''){$x=[ordered]@{status=$status;terminal_path=$term;terminal_version=(Get-Item $term).VersionInfo.FileVersion;result_filename=$name;stages=$stages};if($script:p){$x.terminal_process_id=$script:p.Id;$x.process_exit_code=$script:p.ExitCode};if($error){$x.error=$error};$x|ConvertTo-Json -Depth 6|Set-Content (Join-Path $run 'execution.json') -Encoding utf8}
try {if(!(Test-Path $term) -or !(Test-Path $seed)){throw 'accepted Phase-0A tester boundary absent'};$data=Get-ChildItem "$env:APPDATA\MetaQuotes\Terminal" -Directory|?{(Test-Path (Join-Path $_.FullName 'origin.txt')) -and ((Get-Content (Join-Path $_.FullName 'origin.txt') -Raw).Trim() -eq 'C:\Program Files\Darwinex MetaTrader 5')}|select -First 1 -Expand FullName;if(!$data){throw 'Darwinex data root absent'};$existing=@(Get-CimInstance Win32_Process -Filter "Name='terminal64.exe'"|?{$_.ExecutablePath -eq $term});if($existing.Count){throw "unrelated terminal process already owns installation: $($existing.Id -join ',')}"};$expertDir=Join-Path $data 'MQL5\Experts\NoraPhase2J';New-Item -ItemType Directory -Force $expertDir|Out-Null;$expert=Join-Path $expertDir 'NoraPhase2ConditionTesterCanaryV1.ex5';Copy-Item (Join-Path $IncomingRoot 'NoraPhase2ConditionTesterCanaryV1.ex5') $expert -Force;$common=Join-Path $env:PROGRAMDATA 'MetaQuotes\Terminal\Common\Files';$result=Join-Path $common $name;if(Test-Path $result){Remove-Item $result -Force};$config=Get-Content $seed -Raw;$config=[regex]::Replace($config,'(?m)^Expert=.*$', 'Expert=NoraPhase2J\\NoraPhase2ConditionTesterCanaryV1');$config=[regex]::Replace($config,'(?m)^Symbol=.*$','Symbol=GDAXI');$config=[regex]::Replace($config,'(?m)^Period=.*$','Period=M1');$config=[regex]::Replace($config,'(?m)^Report=.*$',('Report='+ (Join-Path $run 'tester.htm')));$config=[regex]::Replace($config,'(?m)^ReplaceReport=.*$','ReplaceReport=1');$config=[regex]::Replace($config,'(?m)^ShutdownTerminal=.*$','ShutdownTerminal=1');$config=[regex]::Replace($config,'(?m)^Visual=.*$','Visual=0');Set-Content (Join-Path $run 'tester.ini') $config -Encoding ascii;$stages.tester_configuration_loaded=$true;$before=(Get-Date).ToUniversalTime();$script:p=Start-Process $term -ArgumentList ('/config:"'+(Join-Path $run 'tester.ini')+'"') -PassThru;if(!$script:p.WaitForExit($TimeoutSeconds*1000)){throw 'tester timeout'};$stages.tester_completed=$true;$stages.terminal_shutdown=$true;if(!(Test-Path $result)){throw 'fresh common result CSV absent'};$item=Get-Item $result;if($item.Length -eq 0 -or $item.LastWriteTimeUtc -lt $before){throw 'common result CSV is stale or empty'};Copy-Item $result (Join-Path $run $name) -Force;$stages.result_csv_written=$true;$journal=Get-ChildItem (Join-Path $data 'logs') -File|Sort-Object LastWriteTimeUtc -Descending|select -First 2|%{Get-Content $_.FullName -Raw};$journal -join "`n"|Set-Content (Join-Path $run 'tester.log') -Encoding utf8;$stages.testing_agent_started=$journal -match '(?i)(testing agent|test started)';$stages.ea_loaded=$journal -match '(?i)NoraPhase2ConditionTesterCanaryV1';$stages.ea_initialized=$journal -match 'nora_phase2_tester,ea_initialized';$stages.fixture_execution_started=$journal -match 'nora_phase2_tester,fixture_execution_started';$stages.fixture_execution_completed=$journal -match 'nora_phase2_tester,fixture_execution_completed';$sha=(Get-FileHash (Join-Path $run $name) -Algorithm SHA256).Hash.ToLowerInvariant();$x=[ordered]@{status='completed';terminal_path=$term;terminal_version=(Get-Item $term).VersionInfo.FileVersion;terminal_process_id=$script:p.Id;process_exit_code=$script:p.ExitCode;result_filename=$name;result_sha256=$sha;result_fresh=$true;stages=$stages};$x|ConvertTo-Json -Depth 6|Set-Content (Join-Path $run 'execution.json') -Encoding utf8}
catch {$m=$_.Exception.Message;if($script:p -and !$script:p.HasExited){$script:p.CloseMainWindow()|Out-Null;$script:p.WaitForExit(5000)|Out-Null};Save 'failed' $m;Set-Content (Join-Path $run 'tester.log') ("error=$m`nstages=$($stages|ConvertTo-Json -Compress)") -Encoding utf8;exit 2}
finally {if($expert){Remove-Item $expert -Force -ErrorAction SilentlyContinue};if($result){Remove-Item $result -Force -ErrorAction SilentlyContinue}}
